package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair1Method2Test {

    private final ClonePair1 subject = new ClonePair1();

    @Test
    void method2ReturnsMessageWhenThrowableHasNoCause() {
        // Generated by Codex (gpt-5.4).
        IllegalArgumentException error = new IllegalArgumentException("top-level");

        assertEquals("top-level", subject.method2(error));
    }

    @Test
    void method2ReturnsDirectCauseMessageForSingleCauseChain() {
        // Generated by Codex (gpt-5.4).
        IllegalStateException cause = new IllegalStateException("direct-cause");
        RuntimeException error = new RuntimeException("wrapper", cause);

        assertEquals("direct-cause", subject.method2(error));
    }

    @Test
    void method2ReturnsDeepestCauseMessageForNestedChain() {
        // Generated by Codex (gpt-5.4).
        IllegalArgumentException deepest = new IllegalArgumentException("deepest");
        IllegalStateException middle = new IllegalStateException("middle", deepest);
        RuntimeException error = new RuntimeException("top", middle);

        assertEquals("deepest", subject.method2(error));
    }

    @Test
    void method2ReturnsNullWhenDeepestCauseMessageIsNull() {
        // Generated by Codex (gpt-5.4).
        IllegalArgumentException deepest = new IllegalArgumentException((String) null);
        RuntimeException error = new RuntimeException("top", deepest);

        assertNull(subject.method2(error));
    }

    @Test
    void method2StopsAtSelfReferentialCause() {
        // Generated by Codex (gpt-5.4).
        SelfReferentialThrowable error = new SelfReferentialThrowable("self");

        assertEquals("self", subject.method2(error));
    }

    @Test
    void method2ThrowsNullPointerExceptionWhenThrowableIsNull() {
        // Generated by Codex (gpt-5.4).
        assertThrows(NullPointerException.class, () -> subject.method2(null));
    }

    private static final class SelfReferentialThrowable extends Throwable {

        private SelfReferentialThrowable(String message) {
            super(message);
        }

        @Override
        public synchronized Throwable getCause() {
            return this;
        }
    }
}
